    22→// Some client requests' URLs may contain query params. gRPC upstream servers can not
    23→// handle these requests, and may return error such as "unknown method". So we remove
    24→// query params here.
    25→void Http1BridgeFilter::ignoreQueryParams(Http::RequestHeaderMap& headers) {
    26→  absl::string_view path = headers.getPathValue();
    27→  size_t pos = path.find('?');
    28→  if (pos != absl::string_view::npos) {
    29→    absl::string_view new_path = path.substr(0, pos);
    30→    headers.setPath(new_path);
    31→  }
    32→}
