    34→Http::FilterHeadersStatus Http1BridgeFilter::decodeHeaders(Http::RequestHeaderMap& headers, bool) {
    35→  const bool protobuf_request = Grpc::Common::isProtobufRequestHeaders(headers);
    36→  if (upgrade_protobuf_ && protobuf_request) {
    37→    do_framing_ = true;
    38→    headers.setContentType(Http::Headers::get().ContentTypeValues.Grpc);
    39→    headers.setReferenceContentType(Http::Headers::get().ContentTypeValues.Grpc);
    40→    headers.removeContentLength(); // message length part of the gRPC frame
    41→    decoder_callbacks_->downstreamCallbacks()->clearRouteCache();
    42→  }
    43→
    44→  const bool grpc_request = Grpc::Common::isGrpcRequestHeaders(headers);
    45→  const absl::optional<Http::Protocol>& protocol = decoder_callbacks_->streamInfo().protocol();
    46→  ASSERT(protocol);
    47→  if (protocol.value() < Http::Protocol::Http2 && grpc_request) {
    48→    do_bridging_ = true;
    49→  }
    50→
    51→  if (do_bridging_ && ignore_query_parameters_) {
    52→    ignoreQueryParams(headers);
    53→  }
    54→  return Http::FilterHeadersStatus::Continue;
    55→}
