    57→Http::FilterDataStatus Http1BridgeFilter::decodeData(Buffer::Instance& data, bool end_stream) {
    58→  if (!do_bridging_ || !do_framing_) {
    59→    return Http::FilterDataStatus::Continue;
    60→  }
    61→
    62→  decoder_callbacks_->addDecodedData(data, true);
    63→  if (end_stream && do_framing_) {
    64→    decoder_callbacks_->modifyDecodingBuffer(
    65→        [](Buffer::Instance& buf) { Grpc::Common::prependGrpcFrameHeader(buf); });
    66→    return Http::FilterDataStatus::Continue;
    67→  }
    68→
    69→  return Http::FilterDataStatus::StopIterationAndBuffer;
    70→}
