    99→Http::FilterTrailersStatus Http1BridgeFilter::encodeTrailers(Http::ResponseTrailerMap& trailers) {
   100→
   101→  if (do_bridging_) {
   102→    // Here we check for grpc-status. If it's not zero, we change the response code. We assume
   103→    // that if a reset comes in and we disconnect the HTTP/1.1 client it will raise some type
   104→    // of exception/error that the response was not complete.
   105→    const Http::HeaderEntry* grpc_status_header = trailers.GrpcStatus();
   106→    if (grpc_status_header) {
   107→      uint64_t grpc_status_code;
   108→      if (!absl::SimpleAtoi(grpc_status_header->value().getStringView(), &grpc_status_code) ||
   109→          grpc_status_code != 0) {
   110→        response_headers_->setStatus(enumToInt(Http::Code::ServiceUnavailable));
   111→      }
   112→      response_headers_->setGrpcStatus(grpc_status_header->value().getStringView());
   113→    }
   114→
   115→    const Http::HeaderEntry* grpc_message_header = trailers.GrpcMessage();
   116→    if (grpc_message_header) {
   117→      response_headers_->setGrpcMessage(grpc_message_header->value().getStringView());
   118→    }
   119→
   120→    // Since we are buffering, set content-length so that HTTP/1.1 callers can better determine
   121→    // if this is a complete response.
   122→    response_headers_->setContentLength(
   123→        encoder_callbacks_->encodingBuffer() ? encoder_callbacks_->encodingBuffer()->length() : 0);
   124→  }
   125→
   126→  // NOTE: We will still write the trailers, but the HTTP/1.1 codec will just eat them and end
   127→  //       the chunk encoded response which is what we want.
   128→  return Http::FilterTrailersStatus::Continue;
   129→}
