    39→Grpc::Status::GrpcStatus grpcStatusFromHeaders(Http::ResponseHeaderMap& headers) {
    40→  const auto http_response_status = Http::Utility::getResponseStatus(headers);
    41→
    42→  // Notably, we treat an upstream 200 as a successful response. This differs
    43→  // from the standard but is key in being able to transform a successful
    44→  // upstream HTTP response into a gRPC response.
    45→  if (http_response_status == 200) {
